from dataclasses import dataclass, field
from datetime import datetime


@dataclass
class PomodoroRecord:
    pomodoro_number: int
    prompt_change_description: str      # what changed and why
    eval_pass_rate_before: float        # e.g. 0.82
    eval_pass_rate_after: float
    sampled_outputs_reviewed: int       # how many outputs the pair reviewed together
    safety_concerns_raised: list[str]   # notes from the reviewer
    adversarial_inputs_noted: list[str] # new test cases to add to the eval suite
    commit_sha: str = ""
    timestamp: str = ""

    @property
    def eval_delta(self) -> float:
        return self.eval_pass_rate_after - self.eval_pass_rate_before

    @property
    def is_regression(self) -> bool:
        return self.eval_delta < -0.02   # more than 2pp drop is a regression

    def summary(self) -> str:
        direction = "▲" if self.eval_delta >= 0 else "▼"
        return (
            f"Pomodoro {self.pomodoro_number}: {direction}{abs(self.eval_delta):.0%} eval delta "            f"| {len(self.safety_concerns_raised)} safety concerns "            f"| {len(self.adversarial_inputs_noted)} new adversarial inputs"
        )


@dataclass
class PairingSession:
    setup: PairingSessionSetup
    pomodoros: list[PomodoroRecord] = field(default_factory=list)
    started_at: str = ""

    def add_pomodoro(self, record: PomodoroRecord) -> None:
        self.pomodoros.append(record)

    def has_regression(self) -> bool:
        return any(p.is_regression for p in self.pomodoros)

    def total_adversarial_inputs(self) -> list[str]:
        return [inp for p in self.pomodoros for inp in p.adversarial_inputs_noted]

    def final_eval_rate(self) -> float:
        if not self.pomodoros:
            return 0.0
        return self.pomodoros[-1].eval_pass_rate_after

    def session_summary(self) -> dict:
        return {
            "feature_id": self.setup.feature_id,
            "pomodoros_completed": len(self.pomodoros),
            "eval_start": self.pomodoros[0].eval_pass_rate_before if self.pomodoros else None,
            "eval_end": self.final_eval_rate(),
            "regressions": sum(1 for p in self.pomodoros if p.is_regression),
            "new_adversarial_inputs": len(self.total_adversarial_inputs()),
            "safety_concerns_total": sum(len(p.safety_concerns_raised) for p in self.pomodoros),
        }

@dataclass
class SessionHandoff:
    session: PairingSession
    prompt_file_path: str        # path to the committed system prompt
    eval_dataset_path: str       # current eval dataset (may have new cases added)
    open_adversarial_inputs: list[str]   # inputs noted but not yet in the eval suite
    next_steps: list[str]                # what the next pair should tackle first
    known_regressions: list[str]         # eval cases currently failing

    def is_complete(self) -> bool:
        return bool(self.prompt_file_path and self.next_steps)

    def handoff_notes(self) -> str:
        lines = [
            f"Session: {self.session.setup.feature_id} / {self.session.setup.goal.value}",
            f"Eval: {self.session.final_eval_rate():.0%} pass rate at end of session",
            f"Prompt file: {self.prompt_file_path}",
            f"Open adversarial inputs ({len(self.open_adversarial_inputs)}): ",
        ]
        for inp in self.open_adversarial_inputs:
            lines.append(f"  - {inp}")
        lines.append("Next steps:")
        for step in self.next_steps:
            lines.append(f"  1. {step}")
        if self.known_regressions:
            lines.append(f"Known regressions ({len(self.known_regressions)}): {self.known_regressions}")
        return "\n".join(lines)

from dataclasses import dataclass
from typing import Sequence


@dataclass
class PairingMetricsSummary:
    feature_id: str
    sessions: list[PairingSession]

    def eval_improvement_per_session(self) -> list[float]:
        """Net eval pass-rate gain per session."""        return [
            s.final_eval_rate() - s.pomodoros[0].eval_pass_rate_before
            for s in self.sessions
            if s.pomodoros
        ]

    def adversarial_input_growth(self) -> list[int]:
        """Cumulative adversarial inputs after each session."""        total = 0
        result = []
        for s in self.sessions:
            total += len(s.total_adversarial_inputs())
            result.append(total)
        return result

    def regression_rate(self) -> float:
        """Fraction of Pomodoros that introduced a regression."""        all_poms = [p for s in self.sessions for p in s.pomodoros]
        if not all_poms:
            return 0.0
        return sum(1 for p in all_poms if p.is_regression) / len(all_poms)

    def report(self) -> dict:
        return {
            "feature_id": self.feature_id,
            "sessions": len(self.sessions),
            "avg_eval_gain_per_session": (
                sum(self.eval_improvement_per_session()) /
                len(self.eval_improvement_per_session())
                if self.eval_improvement_per_session() else 0.0
            ),
            "total_adversarial_inputs": self.adversarial_input_growth()[-1]
                if self.adversarial_input_growth() else 0,
            "regression_rate": self.regression_rate(),
        }

# Healthy targets for a mature pairing practice:
# avg_eval_gain_per_session: >= 0.05 (5pp per session)
# regression_rate: <= 0.10 (< 10% of Pomodoros regress)
# total_adversarial_inputs: growing each session (reviewer is finding new edge cases)
